class Solution {
    public String minimizeStringValue(String s) {
        int n = s.length();
        int[] count = new int[26];
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) != '?') {
                count[s.charAt(i) - 'a']++;
            }
        }
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '?') {
                char c = 'a';
                while (count[c - 'a'] > 0) {
                    c++;
                }
                res.append(c);
                count[c - 'a']++;
            } else {
                res.append(s.charAt(i));
            }
        }
        return res.toString();
    }
}
